### 7. Compose the main ModelConfigPopover

```tsx
export function ModelConfigPopover({
  model,
  onChangeModel,
  effort,
  onChangeEffort,
  fastMode,
  onChangeFastMode,
  autoMode,
  onChangeAutoMode,
  disabled,
}: ModelConfigPopoverProps) {
  const { data: models, isLoading, isError, refetch } = useModels();
  const selectedModel = models?.find((m) => m.value === model);
  const effortLevels = selectedModel?.supportedEffortLevels;
  const showEffort = selectedModel?.supportsEffort && effortLevels && effortLevels.length > 0;
  const showMode = selectedModel?.supportsFastMode || selectedModel?.supportsAutoMode;

  function getModelLabel(modelId: string): string {
    const option = models?.find((o) => o.value === modelId);
    if (option) return option.displayName;
    const match = modelId.match(/claude-(\w+)-/);
    return match ? match[1].charAt(0).toUpperCase() + match[1].slice(1) : modelId;
  }

  const trigger = (
    <button
      disabled={disabled}
      className="hover:text-foreground inline-flex items-center gap-1 transition-colors duration-150 disabled:cursor-not-allowed disabled:opacity-40"
    >
      <Bot className="size-(--size-icon-xs)" />
      <span>{getModelLabel(model)}</span>
      {effort && (
        <span className="text-muted-foreground text-[10px]">
          {EFFORT_LABELS[effort]}
        </span>
      )}
      {fastMode && (
        <span className="text-muted-foreground text-[10px]">Fast</span>
      )}
    </button>
  );

  if (disabled) {
    return (
      <Tooltip>
        <TooltipTrigger asChild>
          <span className="inline-flex">{trigger}</span>
        </TooltipTrigger>
        <TooltipContent side="top">Send a message first</TooltipContent>
      </Tooltip>
    );
  }

  return (
    <Popover>
      <PopoverTrigger asChild>{trigger}</PopoverTrigger>
      <PopoverContent side="top" align="start" className="w-72 p-3">
        {/* Model cards */}
        {isLoading && <ModelCardSkeleton />}
        {isError && <ModelCardError onRetry={() => refetch()} />}
        {models && models.length > 0 && (
          <div className="space-y-1.5">
            {models.map((m) => (
              <ModelCard
                key={m.value}
                model={m}
                isSelected={m.value === model}
                onSelect={() => onChangeModel(m.value)}
              />
            ))}
          </div>
        )}

        {/* Configuration section */}
        <AnimatePresence>
          {(showEffort || showMode) && (
            <motion.div
              initial={{ opacity: 0, height: 0 }}
              animate={{ opacity: 1, height: 'auto' }}
              exit={{ opacity: 0, height: 0 }}
              transition={{ duration: 0.15 }}
            >
              <div className="bg-border my-3 h-px" />
              <p className="text-muted-foreground mb-2 text-[10px] font-medium uppercase tracking-wider">
                Configuration
              </p>

              {showEffort && (
                <div className="mb-2">
                  <p className="text-muted-foreground mb-1 text-xs">Effort</p>
                  <EffortPills
                    levels={effortLevels!}
                    value={effort}
                    onChange={onChangeEffort}
                  />
                </div>
              )}

              {showMode && selectedModel && (
                <div>
                  <p className="text-muted-foreground mb-1 text-xs">Mode</p>
                  <ModeToggles
                    model={selectedModel}
                    fastMode={fastMode}
                    onChangeFastMode={onChangeFastMode}
                    autoMode={autoMode}
                    onChangeAutoMode={onChangeAutoMode}
                  />
                </div>
              )}
            </motion.div>
          )}
        </AnimatePresence>
      </PopoverContent>
    </Popover>
  );
}
